diff --git a/server/index.js b/server/index.js
index 1c43fa2..7ffa4f6 100644
--- a/server/index.js
+++ b/server/index.js
@@ -27,6 +27,33 @@ app.get('/items/:id', (req, res) => {
   res.json({ item });
 });

+app.post('/items/import', (req, res) => {
+  if (!req.body || !Array.isArray(req.body.items)) {
+    res.status(400).json({ error: 'invalid_body' });
+    return;
+  }
+
+  for (const [index, item] of req.body.items.entries()) {
+    if (!item || typeof item.name !== 'string' || item.name.trim().length === 0) {
+      res.status(400).json({ error: 'invalid_batch', index, field: 'name' });
+      return;
+    }
+    if (typeof item.qty !== 'number' || !Number.isInteger(item.qty) || item.qty <= 0) {
+      res.status(400).json({ error: 'invalid_batch', index, field: 'qty' });
+      return;
+    }
+  }
+
+  const nextId = Math.max(0, ...items.map((item) => item.id)) + 1;
+  const imported = req.body.items.map((item, index) => ({
+    id: nextId + index,
+    name: item.name,
+    qty: item.qty,
+  }));
+  items.push(...imported);
+  res.status(201).json({ inserted: imported.length });
+});
+
 if (require.main === module) {
   const port = Number(process.env.PORT) || 3000;
   app.listen(port, () => {
diff --git a/tests/server.test.js b/tests/server.test.js
index adc6067..d79b87f 100644
--- a/tests/server.test.js
+++ b/tests/server.test.js
@@ -17,12 +17,34 @@ function get(server, path) {
       .get(`http://127.0.0.1:${port}${path}`, (res) => {
         let body = '';
         res.on('data', (chunk) => (body += chunk));
-        res.on('end', () => resolve({ status: res.statusCode, body: JSON.parse(body) }));
+        res.on('end', () => resolve({ status: res.statusCode, body: JSON.parse(body), text: body }));
       })
       .on('error', reject);
   });
 }

+function post(server, path, body) {
+  return new Promise((resolve, reject) => {
+    const { port } = server.address();
+    const request = http.request(
+      `http://127.0.0.1:${port}${path}`,
+      {
+        method: 'POST',
+        headers: { 'content-type': 'application/json' },
+      },
+      (res) => {
+        let responseBody = '';
+        res.on('data', (chunk) => (responseBody += chunk));
+        res.on('end', () => {
+          resolve({ status: res.statusCode, body: JSON.parse(responseBody) });
+        });
+      },
+    );
+    request.on('error', reject);
+    request.end(JSON.stringify(body));
+  });
+}
+
 test('GET /health returns ok', async () => {
   const server = await startServer();
   try {
@@ -56,3 +78,49 @@ test('GET /items/:id returns 404 for missing', async () => {
     server.close();
   }
 });
+
+test('POST /items/import rejects an invalid middle item without changing the list', async () => {
+  const server = await startServer();
+  try {
+    const before = await get(server, '/items');
+    const response = await post(server, '/items/import', {
+      items: [
+        { name: 'gamma', qty: 1 },
+        { name: 'delta', qty: 0 },
+        { name: 'epsilon', qty: 2 },
+      ],
+    });
+    const after = await get(server, '/items');
+
+    assert.strictEqual(response.status, 400);
+    assert.deepStrictEqual(response.body, { error: 'invalid_batch', index: 1, field: 'qty' });
+    assert.strictEqual(after.text, before.text);
+  } finally {
+    server.close();
+  }
+});
+
+test('POST /items/import appends a fully valid batch in order with unique ids', async () => {
+  const server = await startServer();
+  try {
+    const before = await get(server, '/items');
+    const response = await post(server, '/items/import', {
+      items: [
+        { name: 'gamma', qty: 1 },
+        { name: 'delta', qty: 2 },
+      ],
+    });
+    const after = await get(server, '/items');
+    const imported = after.body.items.slice(before.body.items.length);
+
+    assert.strictEqual(response.status, 201);
+    assert.deepStrictEqual(response.body, { inserted: 2 });
+    assert.deepStrictEqual(imported.map(({ name, qty }) => ({ name, qty })), [
+      { name: 'gamma', qty: 1 },
+      { name: 'delta', qty: 2 },
+    ]);
+    assert.strictEqual(new Set(after.body.items.map((item) => item.id)).size, after.body.items.length);
+  } finally {
+    server.close();
+  }
+});

```

